import React from 'react';
import { Link } from 'react-router-dom';
import { LayoutDashboard, PlusCircle, List, Home, Wallet } from 'lucide-react';
import { Rectangle } from 'recharts';

const Sidebar = () => {
  return (
    <aside className="sidebar">
      <h2><Wallet /> Finanças</h2>
      <nav>
        {/* Usamos className em vez de style manual */}
        <Link to="/" className="nav-link"><Home size={20} /> Início</Link>
        <Link to="/lancamento" className="nav-link"><PlusCircle size={20} /> Novo Lançamento</Link>
        <Link to="/listagem" className="nav-link"><List size={20} /> Minhas Despesas</Link>
        <Link to="/dashboard" className="nav-link"><LayoutDashboard size={20} /> Dashboard</Link>
        <Link to="/cartoes" className="nav-link"><Rectangle size={20} /> Cartoes</Link>
      </nav>
    </aside>
  );
};

export default Sidebar;
